const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"أدِر مضيف لينكس الخاص بالطابعة — تحقق من صحته وحالة نظام التشغيل. الخدمات وتنظيف القرص وإعدادات النظام ستصل في مراحل لاحقة."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"ما هذا؟"}},body:{t:0,b:{t:2,i:[{t:3}],s:"يعمل FilaMind على حاسوب لينكس الصغير الخاص بالطابعة (المضيف). تقرأ هذه اللوحة صحة هذا الجهاز وحالة نظام التشغيل مباشرةً حتى تكتشف المشكلات — معالج محموم، أو قرص ممتلئ، أو ساعة غير متزامنة — دون فتح الطرفية."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"اقرأ البطاقات الخاصة بحرارة المعالج والذاكرة والقرص والشبكة بنظرة واحدة."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"راقب جدول أكثر العمليات استهلاكًا لمعرفة ما يستخدم المعالج الآن."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"اترك التحديث التلقائي مفعّلًا لعرض حي، أو أوقفه وحدِّث يدويًا."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"المصطلحات المستخدمة هنا"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"قراءة المراقب"}},body:{t:0,b:{t:2,i:[{t:3}],s:"كل ما هنا للقراءة فقط. تتحول الأشرطة إلى الكهرماني بعد 75% وإلى الأحمر بعد 90%. تتحول حرارة المعالج إلى الكهرماني عند 70 °C وإلى الأحمر عند 80 °C. لا يظهر تحذير الاختناق إلا على اللوحات التي تُبلغ عنه (راسبيري باي بشكل أساسي)."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"المضيف"}},def:{t:0,b:{t:2,i:[{t:3}],s:"حاسوب لينكس الصغير (مثل راسبيري باي أو BTT CB1) الذي يشغّل Klipper وMoonraker وFilaMind — منفصل عن متحكمات الطابعة الدقيقة."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"متوسط الحِمل"}},def:{t:0,b:{t:2,i:[{t:3}],s:"عدد العمليات التي كانت تنتظر التشغيل، بمتوسط على 1 / 5 / 15 دقيقة. تقريبًا: قيمة قريبة من عدد الأنوية تعني أن المعالج مشغول؛ وأعلى منها بكثير تعني أنه محمَّل أكثر من طاقته."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"التبديل (Swap)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"مساحة قرص تُستخدم كفائض عندما تمتلئ الذاكرة. الاستخدام الكثيف للتبديل يُبطئ المضيف — وهو مؤشر على نقص الذاكرة."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"الاختناق (Throttling)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"عندما تخفض اللوحة سرعتها لحماية نفسها — عادةً بسبب مصدر طاقة ضعيف (هبوط الجهد) أو فرط الحرارة. يُبلَّغ عنه غالبًا في راسبيري باي."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / مزامنة الساعة"}},def:{t:0,b:{t:2,i:[{t:3}],s:"بروتوكول وقت الشبكة يُبقي ساعة المضيف دقيقة. الساعة غير المتزامنة قد تعطّل تسجيلات الفيديو المتسارع والسجلات وشهادات TLS."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"الإعدادات المحلية (Locale)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"إعدادات لغة المضيف وتخطيط لوحة المفاتيح، يستخدمها نظام التشغيل للنصوص والتواريخ وتخطيط لوحة مفاتيح الطرفية."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"تحديث"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"تحديث تلقائي"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"جارٍ قراءة حالة المضيف…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"المضيف"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"اسم المضيف"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"نظام التشغيل"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"النواة"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"مدة التشغيل"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"المعالج"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"الحرارة"}},load:{t:0,b:{t:2,i:[{t:3}],s:"الحِمل (1·5·15د)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"الأنوية"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"مُختنق"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"الذاكرة"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"RAM"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"التبديل"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"القرص"}},network:{t:0,b:{t:2,i:[{t:3}],s:"الشبكة"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"الواجهة"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"عنوان IP"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"Wi-Fi"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"الإشارة"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"الوقت واللغة"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"المنطقة الزمنية"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"مزامنة الساعة"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"متزامنة"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"جارٍ المزامنة…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"متوقف"}},language:{t:0,b:{t:2,i:[{t:3}],s:"اللغة"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"تخطيط المفاتيح"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"أكثر العمليات استهلاكًا"}},command:{t:0,b:{t:2,i:[{t:3}],s:"الأمر"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"المعالج٪"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"الذاكرة٪"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"المعرّف"}}}}};export{t as default};
